code_string = """from scipy.optimize import minimize
from qiskit import transpile

def run_and_analyze(circuit, aer_sim, graph):
    transpiled_circuit = transpile(circuit, aer_sim, optimization_level=0)
    params = list(transpiled_circuit.parameters)
    initial_value = 0.0
    initial_params = [initial_value] * circuit.num_parameters

    def evaluate(param_values):
        if len(params) == 0:
            job = aer_sim.run(transpiled_circuit, shots=1024)
        else:
            parameter_binds = [{params[i]: [float(param_values[i])] for i in range(len(params))}]
            job = aer_sim.run(transpiled_circuit, shots=1024, parameter_binds=parameter_binds)
        result = job.result()
        raw_counts = result.get_counts(0)
        counts = {}
        for state, count in raw_counts.items():
            clean_state = state.replace(' ', '')
            node_state = clean_state[::-1]
            counts[node_state] = counts.get(node_state, 0) + count
        return -compute_expectation(counts, graph)

    if circuit.num_parameters > 0:
        opt_result = minimize(evaluate, initial_params, method='COBYLA', options={'maxiter': 25})
        final_params = list(opt_result.x)
    else:
        final_params = initial_params

    if len(params) == 0:
        final_job = aer_sim.run(transpiled_circuit, shots=4096)
    else:
        final_binds = [{params[i]: [float(final_params[i])] for i in range(len(params))}]
        final_job = aer_sim.run(transpiled_circuit, shots=4096, parameter_binds=final_binds)
    final_result = final_job.result()
    raw_counts = final_result.get_counts(0)

    node_counts = {}
    for state, count in raw_counts.items():
        clean_state = state.replace(' ', '')
        node_state = clean_state[::-1]
        node_counts[node_state] = node_counts.get(node_state, 0) + count

    ordered = sorted(node_counts.items(), key=lambda item: item[1], reverse=True)
    top_two = [item[0] for item in ordered[:2]]
    return top_two
"""
